create table dirkspzm32.isi_artikel_cfg (
    sid              varchar2(2 char) not null enable,
    artikel_p1_text  varchar2(50 char),
    artikel_p2_text  varchar2(50 char),
    artikel_p3_text  varchar2(50 char),
    artikel_p4_text  varchar2(50 char),
    artikel_p5_text  varchar2(50 char),
    artikel_p6_text  varchar2(50 char),
    artikel_p7_text  varchar2(50 char),
    artikel_p8_text  varchar2(50 char),
    artikel_p9_text  varchar2(50 char),
    artikel_p10_text varchar2(50 char)
);

alter table dirkspzm32.isi_artikel_cfg
    add constraint pk_isi_artikel_cfg primary key ( sid )
        using index enable;


